# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import kotlinx.android.synthetic.main.activity_share.*

class ShareActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)
        
        handleShareIntent()
    }
    
    private fun handleShareIntent() {
        val intent = intent
        if (Intent.ACTION_SEND.equals(intent.action, ignoreCase = true)) {
            when (intent.type) {
                "text/plain" -> {
                    // Handle shared text
                    handleSharedText(intent.getStringExtra(Intent.EXTRA_TEXT))
                }
                "image/*" ->  {
                    // Handle shared image
                    handleSharedImage(intent.getParcelableExtra<Bitmap>(Intent.EXTRA_STREAM) as Bitmap?)
                }
            }
        }
    }
    
    private fun handleSharedText(text: String?) {
        textView.text = text
    }
    
    private fun handleSharedImage(image: Bitmap?) {
        imageView.setImageBitmap(image)
    }
}